// Extract and transform geofence data from Wialon to Google Sheets format
const item = $input.item.json;
const items = [];

// Get the geofences from the response
const geofences = Array.isArray(item) ? item : (item.zones || []);

if (geofences && geofences.length > 0) {
  for (const geofence of geofences) {
    // Determine geofence type based on name or properties
    let tipo = 'otro';
    const nombreLower = (geofence.n || '').toLowerCase();

    if (nombreLower.includes('taller') || nombreLower.includes('faw') || nombreLower.includes('elam')) {
      tipo = 'taller';
    } else if (nombreLower.includes('caseta') || nombreLower.includes('peaje')) {
      tipo = 'caseta';
    } else if (nombreLower.includes('puerto')) {
      tipo = 'puerto';
    } else if (nombreLower.includes('cliente') || nombreLower.includes('entrega')) {
      tipo = 'cliente';
    }

    // Extract center point from geofence
    let lat = null;
    let lng = null;
    let ubicacion = '';

    // Wialon geofences can be circles, polygons, or lines
    if (geofence.b && geofence.b.cen_x && geofence.b.cen_y) {
      // Center point available
      lat = geofence.b.cen_y;
      lng = geofence.b.cen_x;
    } else if (geofence.p && Array.isArray(geofence.p) && geofence.p.length > 0) {
      // Polygon - calculate centroid
      let sumX = 0, sumY = 0;
      for (const point of geofence.p) {
        sumX += point.x;
        sumY += point.y;
      }
      lat = sumY / geofence.p.length;
      lng = sumX / geofence.p.length;
    }

    // Get address if available
    if (geofence.d && geofence.d.address) {
      ubicacion = geofence.d.address;
    } else {
      ubicacion = geofence.n || 'Sin ubicación';
    }

    // Determine status and activity based on type
    let status_entrada, status_salida, actividad_entrada, actividad_salida, prioridad_alerta;

    switch(tipo) {
      case 'taller':
        status_entrada = 'En Taller';
        status_salida = 'Disponible';
        actividad_entrada = 'Mantenimiento';
        actividad_salida = 'Esperando asignación';
        prioridad_alerta = 'media';
        break;
      case 'puerto':
        status_entrada = 'En Puerto';
        status_salida = 'En Ruta';
        actividad_entrada = 'Carga/Descarga';
        actividad_salida = 'Tránsito';
        prioridad_alerta = 'alta';
        break;
      case 'caseta':
        status_entrada = 'En Ruta';
        status_salida = 'En Ruta';
        actividad_entrada = 'Tránsito autopista';
        actividad_salida = 'Tránsito';
        prioridad_alerta = 'baja';
        break;
      case 'cliente':
        status_entrada = 'Descargando';
        status_salida = 'En Ruta';
        actividad_entrada = 'Entrega en curso';
        actividad_salida = 'Tránsito';
        prioridad_alerta = 'alta';
        break;
      default:
        status_entrada = 'En Ruta';
        status_salida = 'En Ruta';
        actividad_entrada = 'Tránsito';
        actividad_salida = 'Tránsito';
        prioridad_alerta = 'baja';
    }

    items.push({
      nombre: geofence.n || 'Sin nombre',
      tipo: tipo,
      ubicacion: ubicacion,
      lat: lat,
      lng: lng,
      status_entrada: status_entrada,
      status_salida: status_salida,
      actividad_entrada: actividad_entrada,
      actividad_salida: actividad_salida,
      prioridad_alerta: prioridad_alerta,
      notas: geofence.d?.dscr || '',
      wialon_id: geofence.id,
      ultima_actualizacion: new Date().toISOString()
    });
  }
}

return items.length > 0 ? items.map(item => ({json: item})) : [{json: {}}];
